solution:
def follow(url, pages, max_hops=5):
    current = url
    for _ in range(max_hops):
        if current not in pages:
            return None
        value = pages[current]
        # jeśli to przekierowanie
        if isinstance(value, dict) and 'redirect' in value:
            current = value['redirect']
            continue
        # jeśli to zawartość
        if isinstance(value, str):
            return value
        return None
    # przekroczenie max_hops
    return None

